  'key_takeaways_sw' => json_encode(["Jifunza ishara zako za mapema za unyogovu.", "Weka mpango wa hatua mbili: mapema na kipindi kinachokua.", "Taja watu wanaokuamini 2-3 kabla ya dharura."]),
